fun Result<IoTHttpClient.HttpResult>.requireSuccess(): IoTHttpClient.HttpResult {
    val result = getOrElse { throw it }
    if (result.code in 200..299) return result
    throw IoTHttpException("HTTP ${result.code}", code = result.code)
}

fun Throwable.isLikelyTimeout(): Boolean {
    if (this is SocketTimeoutException) return true
    val msg = (message ?: "").lowercase(Locale.US)
    return msg.contains("timeout")
}